class LineCounter{constructor(){this.lineStarts=[],this.addNewLine=t=>this.lineStarts.push(t),this.linePos=t=>{let i=0,e=this.lineStarts.length;for(;i<e;){var n=i+e>>1;this.lineStarts[n]<t?i=1+n:e=n}if(this.lineStarts[i]===t)return{line:i+1,col:1};if(0===i)return{line:0,col:t};var r=this.lineStarts[i-1];return{line:i,col:t-r+1}}}}export{LineCounter};